return [{
  "rowIndex": 3,
  "sheetRowId": "QPC-002",
  "headline": "In the quantum realm, electrons can 'see' a magnetic field even where the field itself is zero. This phenomenon, known as the Aharonov-Bohm effect, proves that potentials, not just forces, shape physical reality.",
  "topic": "Aharonov-Bohm",
  "highlights": ["quantum", "Aharonov-Bohm", "potentials", "reality"],
  "bg_image_url": "https://d1q70pf5vjeyhc.cloudfront.net/predictions/16d9857c2859415f997d85df0c81502c/1.jpeg",
  "facebook_caption": "In the quantum realm, reality behaves in ways that challenge our standard intuition. The Aharonov Bohm effect demonstrates that electrons can detect a magnetic field even if they never physically enter the region where that field exists. This discovery shifted our understanding of physics by proving that electromagnetic potentials are more than just mathematical tools. They are physical realities that can influence particles from a distance. By observing these subtle shifts in electron paths, scientists have confirmed the non local nature of the quantum world.",
  "linkedin_caption": "The Aharonov Bohm effect represents a fundamental milestone in quantum mechanics and electromagnetic theory. It illustrates that charged particles are sensitive to the magnetic vector potential even in regions where the magnetic field strength is zero. For professionals in research and technology, this underscores the profound importance of quantum phase shifts in designing precise instrumentation. This phenomenon confirms that the physical state of a system can be altered by potentials that exert no direct classical force. Understanding these mechanisms is essential for the future of quantum computing and advanced electron interferometry."
}];

const rows = $input.item.json?.values || [];
// Columns: 0=ID, 1=Topic, 2=CustomHeadline, 3=Status
const pending = rows
  .map((r, i) => ({ rowIndex: i + 2, id: r[0]||'', topic: r[1]||'', customHeadline: r[2]||'', status: (r[3]||'').toUpperCase().trim() }))
  .filter(r => r.status === 'PENDING' && r.topic);
if (pending.length === 0) {
  throw new Error('NO_PENDING_TOPICS: No PENDING topics found in Image Post Queue.');
}
const first = pending[0];
return [{ json: { rowIndex: first.rowIndex, sheetRowId: first.id, topic: first.topic, customHeadline: first.customHeadline } }];

const factData = $('Find First Pending Topic').item.json;
const topic = factData.customHeadline || factData.topic;
const prompt = `Generate one mind-blowing lesser-known quantum physics or particle physics fact about this topic: "${topic}"\n\nReturn ONLY valid JSON (no markdown):\n{\n  "headline": "A mind-blowing fact between 30 and 34 words long. Use 2-3 engaging, authoritative sentences.",\n  "topic": "one-word physics concept",\n  "highlights": ["List 3-5 central physics concepts or technical terms to highlight. Focus ONLY on the scientific core (e.g. Entanglement, Quarks, Superposition). NEVER highlight common verbs or generic words like 'see', 'zero', 'find', 'make', or 'keep'."],\n  "image_search_query": "specific visual search query for a real photo"\n}`;
return [{ json: {
  gemini_payload: {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: 1000, temperature: 0.85, responseMimeType: "application/json" }
  }
} }];

const fact = $input.item.json;
const prompt = `Describe a stunning, cinematic background image for this physics concept: "${fact.headline}"\n\nVisual style: Cinematic, high-detail, realistic textures, dark background with vibrant energy trails, 3D render feel.\n\nReturn ONLY JSON:\n{\n  "visual_prompt": "Detailed description of the image..."\n}`;
return [{ json: {
  gemini_payload: {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: 500, temperature: 0.9, responseMimeType: "application/json" }
  }
} }];

const res = JSON.parse($input.item.json.candidates[0].content.parts[0].text);
return [{ json: {
  prompt: res.visual_prompt,
  aspect_ratio: "4:5",
  negative_prompt: "text, logo, watermark, blurry, low quality, distorted, cartoon"
} }];

const res = $input.item.json;
const images = res?.images || [];
const url = images.find(u => /\.(jpg|jpeg|png)/i.test(u)) || images[0] || '';
return [{ json: { ...($('Extract Image URL').item.json), ref_image_url: url } }];

const fs = require('fs');
const jobId = Date.now();
const bgN8n  = `/data/manim/scripts/qpc_bg_${jobId}.jpg`;
const refN8n = `/data/manim/scripts/qpc_ref_${jobId}.jpg`;
const outN8n = `/data/manim/renders/qpc_out_${jobId}.png`;
const bgMnm  = bgN8n.replace('/data/manim/scripts/','/manim/scripts/');
const refMnm = refN8n.replace('/data/manim/scripts/','/manim/scripts/');
const outMnm = outN8n.replace('/data/manim/renders/','/manim/renders/');

const bgBuf = await this.helpers.getBinaryDataBuffer(0, 'data');
fs.writeFileSync(bgN8n, bgBuf);

let hasRef = false;
try {
  const refNode = $('Download Reference Photo').item;
  if (refNode?.binary?.data) {
    const rb = await this.helpers.getBinaryDataBuffer(0, 'data', refNode);
    if (rb && rb.length > 1000) { fs.writeFileSync(refN8n, rb); hasRef = true; }
  }
} catch(e) {}

const factData = $input.item.json;
const config = JSON.stringify({
  bg_path:     bgMnm,
  ref_path:    hasRef ? refMnm : '',
  output_path: outMnm,
  headline:    factData.headline,
  highlights:  factData.highlights || []
});
return [{ json: {
  config, jobId, outN8n,
  rowIndex:          factData.rowIndex,
  sheetRowId:        factData.sheetRowId,
  headline:          factData.headline,
  facebook_caption:  factData.facebook_caption,
  linkedin_caption:  factData.linkedin_caption,
  instagram_caption: factData.instagram_caption,
  tiktok_caption:    factData.tiktok_caption
} }];

const { execSync } = require('child_process');
const config = $input.item.json.config;
const escapedConfig = config.replace(/"/g, '\\"');
const cmd = `docker exec qpc_manim_runner bash -c "python3 /manim/scripts/composite_physics_post.py '${escapedConfig}'"`;
try {
  const stdout = execSync(cmd, { encoding: 'utf-8', timeout: 300000 });
  return { json: { ...$input.item.json, compositor_stdout: stdout.toString() } };
} catch (e) {
  throw new Error('Compositor failed: ' + (e.stdout || e.message));
}

const fs = require('fs');
const outPath = $('Write Images to Volume').item.json.outN8n;
if (!fs.existsSync(outPath)) throw new Error('Output not found: ' + outPath);
const buf = fs.readFileSync(outPath);
const binary = await this.helpers.prepareBinaryData(buf, 'physics_post.png', 'image/png');
const d = $('Write Images to Volume').item.json;
const now = new Date().toISOString().slice(0,10);
return [{ json: {
  fileName:          `schrodingers_cat_${now}_${d.jobId}.png`,
  rowIndex:          d.rowIndex,
  sheetRowId:        d.sheetRowId,
  headline:          d.headline,
  facebook_caption:  d.facebook_caption,
  linkedin_caption:  d.linkedin_caption,
  instagram_caption: d.instagram_caption,
  tiktok_caption:    d.tiktok_caption
}, binary: { data: binary } }];

const drive = $input.item.json;
const prev  = $('Read Output Image').item.json;
return [{ json: {
  ...prev,
  drive_file_id: drive.id,
  drive_url:     `https://drive.usercontent.google.com/download?id=${drive.id}&export=download&confirm=t`
} }];

const res = $input.item.json;
const fb_post_id  = res?.fb_post_id  || '';
const li_post_id  = res?.li_post_id  || '';
const driveFileId = res?.drive_file_id || '';
const driveUrl    = res?.drive_url    || '';
const headline    = $('Read Output Image').item.json.headline;
const rowIndex    = $('Read Output Image').item.json.rowIndex;
const now = new Date().toISOString();
return [{ json: { rowIndex, fb_post_id, li_post_id, driveFileId, driveUrl, headline, publishedAt: now } }];

const d = $('Read Output Image').item.json;
const drive = $('Upload to Google Drive').item.json;
return [{ json: {
  headline:          d.headline,
  facebook_caption:  d.facebook_caption,
  linkedin_caption:  d.linkedin_caption,
  instagram_caption: d.instagram_caption,
  tiktok_caption:    d.tiktok_caption,
  drive_file_id:     drive.id,
  drive_url:        `https://drive.usercontent.google.com/download?id=${drive.id}&export=download&confirm=t`,
  rowIndex:         d.rowIndex
} }];
